class Solution:
    def characterReplacement(self, s, k):
        n = len(s)
        best = 0
        for start in range(n):
            freq = {}
            for end in range(start, n):
                c = s[end]
                freq[c] = freq.get(c, 0) + 1
                window = end - start + 1
                if window - max(freq.values()) <= k:
                    best = max(best, window)
        return best

